const body = $json.body || $json;
if (!body.action) throw new Error("action zorunlu");

const action = String(body.action).trim().toLowerCase();
const payload = body.payload || {};
const session_key = body.session_key || "";

// Oturum gerektiren action'lar
const SESSION_REQUIRED = [
  "check_quota",
  "upload_receipt",
  "get_reports",
  "get_receipts",
  "update_receipt",
  "delete_receipt",
  "manage_metadata",
  "get_team",
  "add_user",
  "delete_user"
];

if (SESSION_REQUIRED.includes(action) && !session_key) {
  throw new Error("Bu islem icin session_key zorunlu");
}

return [{ json: { action, payload, session_key, _step: 1 } }];

// ================================================================
// DYNAMIC SQL ENGINE - minimal ama tam action kapsami
// ================================================================
const { action, payload, session_key, _step, _prev } = $json;

const OP = String(payload.operation || "").toLowerCase().trim();
const TABLE = String(payload.table || "").toLowerCase().trim();

const TABLE_MAP = {
  categories: "categories",
  projects: "projects",
  company_cards: "company_cards"
};

const getCompanyIdSql = `
  (SELECT u.company_id
   FROM users u
   JOIN user_sessions s ON s.user_id = u.id
   WHERE s.session_key = $1
     AND s.revoked_at IS NULL
   LIMIT 1)
`;

const ACTIONS = {
  // ---------------- AUTH ----------------
  login: {
    1: {
      validate: () => {
        if (!payload.email || !payload.password) {
          throw new Error("E-posta ve sifre zorunlu");
        }
      },
      sql: `
        SELECT u.id, u.company_id, u.role, u.is_super_admin
        FROM users u
        WHERE lower(u.email) = lower($1)
          AND u.password_hash = crypt($2, u.password_hash)
          AND u.status = 'true'
        LIMIT 1
      `,
      params: () => [payload.email, payload.password]
    },
    2: {
      sql: `
        INSERT INTO user_sessions (user_id, session_key, expires_at, user_agent)
        VALUES ($1, encode(gen_random_bytes(32), 'hex'), now() + interval '15 days', $2)
        RETURNING session_key
      `,
      params: () => [_prev.id, payload.user_agent || "web"]
    }
  },

  register: {
    1: {
      validate: () => {
        if (!payload.company_name || !payload.email || !payload.password) {
          throw new Error("Eksik kayit bilgileri");
        }
      },
      sql: `
        SELECT create_trial_company_and_admin(
          $1, $2, crypt($3, gen_salt('bf')), $4
        ) AS user_id
      `,
      params: () => [payload.company_name, payload.email, payload.password, payload.telegram_id || null]
    }
  },

  forgot_password: {
    1: {
      validate: () => {
        if (!payload.email) throw new Error("E-posta zorunlu");
      },
      sql: `
        SELECT id, email, coalesce(full_name, split_part(email, '@', 1)) AS full_name
        FROM users
        WHERE lower(email) = lower($1) AND status = 'true'
        LIMIT 1
      `,
      params: () => [payload.email]
    },
    2: {
      sql: `
        UPDATE users
        SET password_hash = crypt($1, gen_salt('bf')), updated_at = now()
        WHERE id = $2
        RETURNING id
      `,
      params: () => [_prev.temp_password, _prev.user_id]
    }
  },

  // ---------------- SYSTEM ----------------
  check_quota: {
    1: {
      sql: `
        SELECT c.id AS company_id, check_company_quota(c.id) AS allow
        FROM user_sessions s
        JOIN users u ON u.id = s.user_id
        JOIN companies c ON c.id = u.company_id
        WHERE s.session_key = $1
          AND s.revoked_at IS NULL
        LIMIT 1
      `,
      params: () => [session_key]
    }
  },

  get_reports: {
    1: {
      sql: `
        SELECT
          u.id AS user_id,
          u.role,
          u.is_super_admin,
          u.company_id,
          u.full_name,
          u.email,
          c.company_name,
          c.used_this_month,
          c.monthly_limit,
          c.extra_credits,
          c.plan_type,
          c.status
        FROM user_sessions s
        JOIN users u ON u.id = s.user_id
        LEFT JOIN companies c ON c.id = u.company_id
        WHERE s.session_key = $1
          AND s.revoked_at IS NULL
        LIMIT 1
      `,
      params: () => [session_key]
    }
  },

  // ---------------- RECEIPTS ----------------
  get_receipts: {
    1: {
      sql: `
        SELECT f.*
        FROM fisler f
        WHERE f.company_id = ${getCompanyIdSql}
        ORDER BY f.tarih DESC, f.saat DESC
        LIMIT 200
      `,
      params: () => [session_key]
    }
  },

  update_receipt: {
    1: {
      validate: () => {
        if (!payload.receipt_id || !payload.data) throw new Error("ID veya veri eksik");
      },
      sql: `
        UPDATE fisler
        SET
          isletme_adi   = COALESCE($1, isletme_adi),
          toplam_tutar  = COALESCE($2, toplam_tutar),
          tarih         = COALESCE($3, tarih),
          saat          = COALESCE($4, saat),
          durum         = COALESCE($5, durum),
          kategori      = COALESCE($6, kategori),
          proje         = COALESCE($7, proje),
          fis_no        = COALESCE($8, fis_no),
          kart_son_4    = COALESCE($9, kart_son_4),
          ocr_detaylari = COALESCE($10::jsonb, ocr_detaylari)
        WHERE id = $11
          AND company_id = ${getCompanyIdSql}
        RETURNING id
      `,
      params: () => [
        payload.data.isletme_adi ?? null,
        payload.data.toplam_tutar ?? null,
        payload.data.tarih ?? null,
        payload.data.saat ?? null,
        payload.data.durum ?? null,
        payload.data.kategori ?? null,
        payload.data.proje ?? null,
        payload.data.fis_no ?? null,
        payload.data.kart_son_4 ?? null,
        payload.data.ocr_detaylari ? JSON.stringify(payload.data.ocr_detaylari) : null,
        payload.receipt_id,
        session_key
      ]
    }
  },

  delete_receipt: {
    1: {
      validate: () => {
        if (!payload.receipt_id) throw new Error("receipt_id zorunlu");
      },
      sql: `
        DELETE FROM fisler
        WHERE id = $1
          AND company_id = ${getCompanyIdSql}
        RETURNING id
      `,
      params: () => [payload.receipt_id, session_key]
    }
  },

  // ---------------- TEAM ----------------
  get_team: {
    1: {
      sql: `
        SELECT id, email, full_name, role, status, phone_number
        FROM users
        WHERE company_id = ${getCompanyIdSql}
        ORDER BY created_at DESC
      `,
      params: () => [session_key]
    }
  },

  add_user: {
    1: {
      validate: () => {
        if (!payload.email || !payload.full_name || !payload.password) {
          throw new Error("email, full_name ve password zorunlu");
        }
      },
      sql: `
        INSERT INTO users (
          id, company_id, full_name, email, password_hash, phone_number, role, status, is_super_admin, created_at
        )
        VALUES (
          gen_random_uuid(),
          ${getCompanyIdSql},
          $2, $3, crypt($4, gen_salt('bf')), $5, $6, 'true', false, now()
        )
        RETURNING id
      `,
      params: () => [
        session_key,
        payload.full_name,
        payload.email,
        payload.password,
        payload.phone || null,
        payload.role || "user"
      ]
    }
  },

  delete_user: {
    1: {
      validate: () => {
        if (!payload.user_id) throw new Error("user_id zorunlu");
      },
      sql: `
        UPDATE users
        SET status = 'false'
        WHERE id = $1
          AND company_id = ${getCompanyIdSql}
        RETURNING id
      `,
      params: () => [payload.user_id, session_key]
    }
  },

  // ---------------- METADATA ----------------
  manage_metadata: {
    1: {
      validate: () => {
        if (!TABLE_MAP[TABLE]) throw new Error("Gecersiz metadata tablosu");
        if (!["list", "insert", "delete"].includes(OP)) {
          throw new Error("Gecersiz metadata operation");
        }
      },
      sql: (() => {
        const t = TABLE_MAP[TABLE];
        if (OP === "list") {
          if (t === "company_cards") {
            return `
              SELECT id, company_id, bank_name, card_alias, last_4_digits, created_at
              FROM company_cards
              WHERE company_id = ${getCompanyIdSql}
              ORDER BY created_at DESC
            `;
          }
          if (t === "projects") {
            return `
              SELECT id, company_id, name, code, created_at
              FROM projects
              WHERE company_id = ${getCompanyIdSql}
              ORDER BY name ASC
            `;
          }
          return `
            SELECT id, company_id, name, created_at
            FROM categories
            WHERE company_id = ${getCompanyIdSql}
            ORDER BY name ASC
          `;
        }

        if (OP === "insert") {
          if (t === "company_cards") {
            return `
              INSERT INTO company_cards (company_id, bank_name, card_alias, last_4_digits, created_at)
              VALUES (${getCompanyIdSql}, $2, $3, $4, now())
              RETURNING id
            `;
          }
          if (t === "projects") {
            return `
              INSERT INTO projects (company_id, name, code, created_at)
              VALUES (${getCompanyIdSql}, $2, $3, now())
              RETURNING id
            `;
          }
          return `
            INSERT INTO categories (company_id, name, created_at)
            VALUES (${getCompanyIdSql}, $2, now())
            RETURNING id
          `;
        }

        // delete
        return `
          DELETE FROM ${t}
          WHERE id = $2
            AND company_id = ${getCompanyIdSql}
          RETURNING id
        `;
      })(),
      params: () => {
        if (OP === "list") return [session_key];

        if (OP === "insert") {
          if (TABLE === "company_cards") {
            const d = payload.data || {};
            return [
              session_key,
              d.bank_name || "Kredi Karti",
              d.card_alias || (d.last_4_digits ? `Kart ${d.last_4_digits}` : "Kart"),
              d.last_4_digits || null
            ];
          }
          if (TABLE === "projects") {
            const d = payload.data || {};
            return [session_key, d.name || null, d.code || null];
          }
          const d = payload.data || {};
          return [session_key, d.name || null];
        }

        // delete
        return [session_key, payload.id || null];
      }
    }
  }
};

// Action kontrolu
const actionDef = ACTIONS[action];
if (!actionDef) {
  return [{ json: { _done: true, _response: { ok: false, message: "Bilinmeyen islem: " + action } } }];
}

const stepDef = actionDef[_step];
if (!stepDef) {
  return [{ json: { _done: true, _response: { ok: false, message: "Gecersiz adim: " + action + "/" + _step } } }];
}

if (stepDef.validate) stepDef.validate();

return [{
  json: {
    action,
    payload,
    session_key,
    _step,
    _sql: stepDef.sql,
    _params: stepDef.params(),
    _prev: _prev || null
  }
}];

const input = $("SQL Engine").first().json;
const { action, payload, session_key, _step } = input;
const rows = $input.all().map((i) => i.json);
const row = rows[0] || {};

// ---------------- LOGIN ----------------
if (action === "login" && _step === 1) {
  if (!row.id) throw new Error("Hatali giris");
  return [{ json: { action, payload, session_key, _step: 2, _prev: row, _done: false } }];
}
if (action === "login" && _step === 2) {
  return [{ json: { _done: true, _response: { ok: true, session_key: row.session_key } } }];
}

// ---------------- REGISTER ----------------
if (action === "register") {
  return [{ json: { _done: true, _response: { ok: true, message: "Kayit olusturuldu", user_id: row.user_id } } }];
}

// ---------------- QUOTA ----------------
if (action === "check_quota") {
  return [{ json: { _done: true, _response: { ok: true, allow: row.allow || false, company_id: row.company_id || null } } }];
}

// ---------------- REPORTS ----------------
if (action === "get_reports") {
  if (!row.user_id) throw new Error("Gecersiz veya suresi dolmus oturum");
  return [{
    json: {
      _done: true,
      _response: {
        ok: true,
        profile: {
          user_id: row.user_id,
          role: row.role,
          is_super_admin: row.is_super_admin,
          full_name: row.full_name || null,
          email: row.email || null,
          company_id: row.company_id || null
        },
        company: {
          company_id: row.company_id || null,
          company_name: row.company_name || null,
          name: row.company_name || null,
          used_this_month: row.used_this_month || 0,
          monthly_limit: row.monthly_limit || 0,
          extra_credits: row.extra_credits || 0,
          plan_type: row.plan_type || null,
          status: row.status || null
        }
      }
    }
  }];
}

// ---------------- RECEIPTS ----------------
if (action === "get_receipts") {
  const normalized = rows.map((r) => {
    let ocr = r.ocr_detaylari;
    if (ocr && typeof ocr === "object" && Array.isArray(ocr.urunler)) {
      ocr = ocr.urunler;
    }
    return { ...r, ocr_detaylari: ocr || [] };
  });
  return [{ json: { _done: true, _response: { ok: true, receipts: normalized } } }];
}

if (action === "update_receipt") {
  return [{ json: { _done: true, _response: { ok: true, updated_id: row.id || null } } }];
}

if (action === "delete_receipt") {
  return [{ json: { _done: true, _response: { ok: true, deleted_id: row.id || null } } }];
}

// ---------------- TEAM ----------------
if (action === "get_team") {
  return [{ json: { _done: true, _response: { ok: true, users: rows } } }];
}

if (action === "add_user") {
  return [{ json: { _done: true, _response: { ok: true, user_id: row.id || null } } }];
}

if (action === "delete_user") {
  return [{ json: { _done: true, _response: { ok: true, user_id: row.id || null } } }];
}

// ---------------- METADATA ----------------
if (action === "manage_metadata") {
  const table = String(payload.table || "").toLowerCase().trim();
  const op = String(payload.operation || "").toLowerCase().trim();

  if (op === "list") {
    return [{ json: { _done: true, _response: { ok: true, [table]: rows, items: rows } } }];
  }
  if (op === "insert") {
    return [{ json: { _done: true, _response: { ok: true, inserted_id: row.id || null } } }];
  }
  if (op === "delete") {
    return [{ json: { _done: true, _response: { ok: true, deleted_id: row.id || null } } }];
  }

  return [{ json: { _done: true, _response: { ok: false, message: "Gecersiz metadata operation" } } }];
}

// ---------------- FORGOT PASSWORD ----------------
if (action === "forgot_password" && _step === 1) {
  const SAFE_MSG = "Eger e-posta sistemde kayitliysa gecici sifre gonderildi.";

  if (!row.id) {
    return [{ json: { _done: true, _response: { ok: true, message: SAFE_MSG } } }];
  }

  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789";
  let tempPassword = "";
  for (let i = 0; i < 8; i++) tempPassword += chars.charAt(Math.floor(Math.random() * chars.length));

  return [{
    json: {
      action,
      payload,
      session_key,
      _step: 2,
      _prev: { ...row, temp_password: tempPassword, user_id: row.id },
      _done: false,
      _send_mail: true,
      _mail_data: { email: row.email, full_name: row.full_name, temp_password: tempPassword }
    }
  }];
}

if (action === "forgot_password" && _step === 2) {
  const mailData = input._mail_data || input._prev || {};
  return [{
    json: {
      _done: "send_mail",
      _mail_data: mailData,
      _response: { ok: true, message: "Eger e-posta sistemde kayitliysa gecici sifre gonderildi." }
    }
  }];
}

// Fallback
return [{ json: { _done: true, _response: { ok: true, message: "Islem tamamlandi", data: rows } } }];
